import React from 'react'
import styled from 'styled-components'

const importAll = (require) =>
  require.keys().reduce((acc, next) => {
    acc[next.replace('./', '')] = require(next)
    return acc
  }, {})

const images = importAll(require.context('../imgs/stack', false, /\.(png|jpe?g|svg)$/))

export default () => {
  return (
    <Wrapper>
      <div className="container">
        {Object.keys(images).map((key) => (
          <img className="icon" src={images[key]} alt="stack-icon" />
        ))}
      </div>
    </Wrapper>
  )
}

const Wrapper = styled.div`
  display: flex;
  flex-direction: column;
  justify-content: center;
  align-items: center;
  min-width: 100vw;

  .container {
    * {
      margin-right: 1rem;
    }

    width: 90vw;
    display: flex;
  }

  .icon {
    height: 2rem;
  }

  .big {
    color: rgb(255, 255, 255, 0.9);
    font-size: calc(2vmin + 15px);
    font-weight: bold;
    margin-bottom: 3rem;
  }
`
